import styled from "styled-components"

import Nav from './Nav'
import Introduction from "./Introduction"

import github from '../../img/LandingPage/github.svg'
import mail from '../../img/LandingPage/mail.svg'

const LandingPage = () => {
  return (
    <Container>
      <Nav />
      <Introduction />
      <More> More </More>

      <QuickContact>
        <VerticalLine />
        <li>
          <a href="https://github.com/energywraith" rel="noopener noreferrer">
            <img src={github} alt="github logo" />
          </a>
        </li>
        <li>
          <a href="a">
            <img src={mail} alt="mail icon" />
          </a>
        </li>
        <VerticalLine />
      </QuickContact>
    </Container>
  )
}

const Container = styled.section`
  width: 100vw;
  height: 100vh;
  background: black;
  color: white;

  display: grid;
  grid-template: auto 1fr auto / auto auto;
  align-items: center;
  justify-content: space-between;

  font-family: Rubik;
`

const More = styled.span`
  padding: 2em;
`

const QuickContact = styled.ul`
  padding: 0em 1em 5em 0em;
  grid-column: 2;
  grid-row: 2/4;
  display: flex;
  flex-direction: column;
  align-items: center;
  row-gap: 1em;

  & li a {
    display: inline-block;
    padding: 1em;
    width: 2em;
    height: 2em;

    &:hover img {
      filter: invert(0.8)
    }
  }

  & img {
    filter: invert(1) opacity(0.5);
    width: 100%;
    height: 100%;
  }
`

const VerticalLine = styled.hr`
  border: 1px solid rgba(255, 255, 255, 0.5);
  height: 10em;
`

export default LandingPage
